{"status": "success", "output": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>James Chamberlin — Resume</title>
<style>
  /* ── FAANG-STYLE RESUME ──
     Google/Amazon/Meta formatting conventions:
     - Clean sans-serif, tight line spacing
     - Name large, contact inline
     - Bold company + right-aligned dates on same line
     - Role italic beneath company
     - Bullet points: strong action verb · context · quantified result
     - No color blocks, no icons in printed version
     - Skills as a compact grid, not a list paragraph
     - Horizontal rules only between major sections
  */

  :root {
    --text: #1A1A1A;
    --subtext: #444;
    --light: #666;
    --rule: #CCCCCC;
    --link: #1A56EB;
    --accent: #1A56EB;
    --page-width: 780px;
  }

  * { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    font-family: 'Calibri', 'Arial', 'Helvetica Neue', sans-serif;
    font-size: 10.5pt;
    line-height: 1.45;
    color: var(--text);
    background: #F0F0F0;
  }

  .page {
    max-width: var(--page-width);
    margin: 2rem auto;
    background: white;
    padding: 0.7in 0.65in 0.7in;
    box-shadow: 0 2px 20px rgba(0,0,0,0.12);
  }

  /* ── HEADER ── */
  .resume-header {
    text-align: center;
    margin-bottom: 0.5rem;
  }
  .resume-name {
    font-size: 22pt;
    font-weight: 700;
    letter-spacing: -0.5px;
    color: var(--text);
    line-height: 1.1;
  }
  .resume-contact {
    font-size: 9.5pt;
    color: var(--light);
    margin-top: 0.2rem;
    line-height: 1.6;
  }
  .resume-contact a { color: var(--link); text-decoration: none; }
  .resume-contact .sep { margin: 0 0.4rem; color: var(--rule); }

  /* ── SECTIONS ── */
  hr.section-rule {
    border: none;
    border-top: 1.5px solid var(--text);
    margin: 0.3rem 0 0.45rem;
  }
  .section-title {
    font-size: 11pt;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.08em;
    color: var(--text);
    margin-bottom: 0;
  }
  section { margin-bottom: 0.75rem; }

  /* ── SUMMARY ── */
  .summary-text {
    font-size: 10pt;
    color: var(--subtext);
    line-height: 1.5;
    margin-top: 0.35rem;
  }

  /* ── EXPERIENCE ── */
  .job { margin-bottom: 0.65rem; }
  .job-header {
    display: flex;
    justify-content: space-between;
    align-items: baseline;
  }
  .job-company {
    font-size: 11pt;
    font-weight: 700;
    color: var(--text);
  }
  .job-location-dates {
    font-size: 9.5pt;
    color: var(--light);
    text-align: right;
    white-space: nowrap;
  }
  .job-title {
    font-size: 10.5pt;
    font-style: italic;
    color: var(--subtext);
    margin-bottom: 0.3rem;
  }
  .job-desc {
    font-size: 9.8pt;
    color: var(--subtext);
    margin-bottom: 0.3rem;
    line-height: 1.45;
  }

  ul.bullets {
    padding-left: 1.1em;
    list-style: disc;
  }
  ul.bullets li {
    font-size: 10pt;
    color: var(--subtext);
    line-height: 1.5;
    margin-bottom: 0.2rem;
  }
  ul.bullets li strong {
    color: var(--text);
    font-weight: 600;
  }
  ul.bullets li .metric {
    font-weight: 700;
    color: var(--text);
  }

  /* ── SKILLS ── */
  .skills-grid {
    display: grid;
    grid-template-columns: 130px 1fr;
    gap: 0.25rem 0.75rem;
    margin-top: 0.35rem;
  }
  .skill-category {
    font-size: 9.8pt;
    font-weight: 700;
    color: var(--text);
    padding-top: 0.05rem;
  }
  .skill-items {
    font-size: 9.8pt;
    color: var(--subtext);
  }

  /* ── EDUCATION + CERTS ── */
  .edu-row {
    display: flex;
    justify-content: space-between;
    align-items: baseline;
    margin-top: 0.35rem;
  }
  .edu-school { font-size: 10.5pt; font-weight: 700; }
  .edu-degree { font-size: 10pt; font-style: italic; color: var(--subtext); }
  .edu-date   { font-size: 9.5pt; color: var(--light); }

  /* ── PRINT ── */
  @media print {
    body { background: white; }
    .page { margin: 0; padding: 0.5in 0.55in; box-shadow: none; }
    .no-print { display: none; }
  }

  /* ── SCREEN-ONLY TOOLBAR ── */
  .toolbar {
    position: sticky; top: 0; z-index: 50;
    background: #1B2A4A; color: white;
    padding: 0.6rem 1.5rem;
    display: flex; justify-content: space-between; align-items: center;
    font-size: 0.85rem;
    box-shadow: 0 2px 8px rgba(0,0,0,0.2);
  }
  .toolbar strong { color: #14B8A6; }
  .toolbar-note { opacity: 0.7; font-size: 0.78rem; }
  .print-btn {
    background: #0D9488; color: white; border: none;
    padding: 0.4rem 1rem; border-radius: 4px; cursor: pointer;
    font-size: 0.82rem; font-weight: 600;
  }
  .print-btn:hover { background: #0F766E; }
  @media print { .toolbar { display: none; } }
</style>
</head>
